import React, { useEffect, useState } from "react";

import FeatureModal from "../components/FeatureModal";
import axios from "axios";


const API_URL = "http://localhost:5000/api/features";
const AUTH_API_URL = "http://localhost:5000/api/auth/login";
const priorities = ["Low", "Medium", "High"];
const statuses = ["Open", "In Progress", "Completed"];

// ── Lightbox component ────────────────────────────────────────────────────────
function ImageLightbox({ src, alt, onClose }) {
  // Close on Escape key
  useEffect(() => {
    const handleKey = (e) => { if (e.key === "Escape") onClose(); };
    window.addEventListener("keydown", handleKey);
    return () => window.removeEventListener("keydown", handleKey);
  }, [onClose]);

  return (
    <div
      onClick={onClose}
      style={{
        position: "fixed", top: 0, left: 0, width: "100vw", height: "100vh",
        background: "rgba(0,0,0,0.82)", display: "flex", alignItems: "center",
        justifyContent: "center", zIndex: 9999, cursor: "zoom-out",
        backdropFilter: "blur(4px)",
      }}
    >
      <div
        onClick={e => e.stopPropagation()}
        style={{
          position: "relative", maxWidth: "90vw", maxHeight: "90vh",
          borderRadius: 12, overflow: "hidden",
          boxShadow: "0 8px 48px rgba(0,0,0,0.7)",
        }}
      >
        <img
          src={src}
          alt={alt}
          style={{ display: "block", maxWidth: "90vw", maxHeight: "85vh", objectFit: "contain" }}
        />
        {/* Close button */}
        <button
          onClick={onClose}
          style={{
            position: "absolute", top: 10, right: 10,
            background: "rgba(0,0,0,0.55)", color: "#fff", border: "none",
            borderRadius: "50%", width: 34, height: 34, fontSize: 18,
            cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center",
            lineHeight: 1,
          }}
          title="Close (Esc)"
        >✕</button>
      </div>
    </div>
  );
}

export default function AdminDashboard() {
  const [features, setFeatures] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [errorDetails, setErrorDetails] = useState(null);
  const [editingId, setEditingId] = useState(null);
  const [editData, setEditData] = useState({});
  const [editImageFile, setEditImageFile] = useState(null);   // ← new: image file for inline edit
  const [newFeature, setNewFeature] = useState({ title: "", description: "", priority: "Low", status: "Open" });
  const [adding, setAdding] = useState(false);
  const [showPriorityDialog, setShowPriorityDialog] = useState(false);
  const [lastAddedId, setLastAddedId] = useState(null);
  const [priorityToSet, setPriorityToSet] = useState("Low");
  // Admin login state
  const [user, setUser] = useState(null);
  const [loginForm, setLoginForm] = useState({ username: "", password: "" });
  const [loginError, setLoginError] = useState(null);
  const [imageFile, setImageFile] = useState(null);
  // Delete confirmation dialog state
  const [deleteConfirm, setDeleteConfirm] = useState(null);
  // ── Lightbox state ────────────────────────────────────────────────────────
  const [lightbox, setLightbox] = useState(null); // { src, alt } or null

  // Fetch features
  const fetchFeatures = () => {
    setLoading(true);
    setError(null);
    setErrorDetails(null);
    axios.get(API_URL)
      .then(res => setFeatures(res.data))
      .catch(err => {
        setError("Failed to fetch features");
        setErrorDetails(err?.message || JSON.stringify(err));
        console.error("Fetch features error:", err);
      })
      .finally(() => setLoading(false));
  };

  useEffect(() => { fetchFeatures(); }, []);
  // Simple admin login handler
  const handleLogin = async (e) => {
    e.preventDefault();
    setLoginError(null);
    try {
      const res = await axios.post(AUTH_API_URL, loginForm);
      if (res.data && res.data.success) {
        setUser({ username: loginForm.username });
      } else {
        setLoginError("Invalid credentials");
      }
    } catch (err) {
      setLoginError("Invalid credentials");
    }
  };
  const handleLogout = () => {
    setUser(null);
  };

  // Add, edit, delete handlers (implement as needed)
  const handleAdd = async () => {
    if (!newFeature.title.trim() || !newFeature.description.trim()) {
      setError("Title and description are required.");
      return;
    }
    setError(null);
    setLoading(true);
    try {
      const formData = new FormData();
      formData.append("title", newFeature.title);
      formData.append("description", newFeature.description);
      formData.append("priority", newFeature.priority);
      formData.append("status", newFeature.status);
      if (imageFile) {
        formData.append("image", imageFile);
      }
      const res = await axios.post(API_URL, formData, {
        headers: { "Content-Type": "multipart/form-data" }
      });
      setFeatures(f => [...f, res.data]);
      setNewFeature({ title: "", description: "", priority: "Low", status: "Open" });
      setImageFile(null);
      setAdding(false);
      setLastAddedId(res.data.id || res.data._id);
      setShowPriorityDialog(true);
    } catch (err) {
      setError("Failed to add feature");
      setErrorDetails(err?.message || JSON.stringify(err));
    } finally {
      setLoading(false);
    }
  };

  // Edit feature: set editing state and prefill editData
  const handleEdit = (feature) => {
    setEditingId(feature.id);
    setEditImageFile(null); // reset image file on new edit session
    setEditData({
      title: feature.title,
      description: feature.description,
      priority: feature.priority,
      status: feature.status
    });
  };

  // Save edited feature
  const handleSave = async (id) => {
    setLoading(true);
    setError(null);
    try {
      const feature = features.find(f => f.id === id);
      const data = new FormData();
      data.append('title', editData.title);
      data.append('description', editData.description);
      data.append('priority', editData.priority);
      data.append('status', editData.status);

      if (editImageFile) {
        // User picked a new image — upload it
        data.append('image', editImageFile);
      } else if (feature && feature.image && !(feature.image instanceof File)) {
        // Keep existing image: pass the filename so the backend knows to retain it
        data.append('existingImage', feature.image);
      }

      await axios.put(`${API_URL}/${id}`, data, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      setEditingId(null);
      setEditData({});
      setEditImageFile(null);
      fetchFeatures();
    } catch (err) {
      setError('Failed to save feature');
      setErrorDetails(err?.message || JSON.stringify(err));
    } finally {
      setLoading(false);
    }
  };

  // Delete feature
  const handleDelete = async (id) => {
    setLoading(true);
    setError(null);
    try {
      await axios.delete(`${API_URL}/${id}`);
      setFeatures(f => f.filter(feat => feat.id !== id));
      setDeleteConfirm(null);
    } catch (err) {
      setError('Failed to delete feature');
      setErrorDetails(err?.message || JSON.stringify(err));
    } finally {
      setLoading(false);
    }
  };

  // ── Helper: resolve image URL ─────────────────────────────────────────────
  const imgSrc = (filename) => `http://localhost:5000/api/features/images/${filename}`;

  // Render
  if (!user) {
    return (
      <div style={{ maxWidth: 400, margin: "80px auto", background: "#fff", borderRadius: 12, padding: 32, color: '#222', boxShadow: '0 2px 16px #0001' }}>
        <h2 style={{ fontSize: 28, marginBottom: 24, fontWeight: 800 }}>Admin Login</h2>
        <form onSubmit={handleLogin} style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          <input
            type="text"
            placeholder="Username"
            value={loginForm.username}
            onChange={e => setLoginForm(f => ({ ...f, username: e.target.value }))}
            style={{ padding: 8, borderRadius: 4, border: '1px solid #ccc' }}
            autoFocus
          />
          <input
            type="password"
            placeholder="Password"
            value={loginForm.password}
            onChange={e => setLoginForm(f => ({ ...f, password: e.target.value }))}
            style={{ padding: 8, borderRadius: 4, border: '1px solid #ccc' }}
          />
          {loginError && <div style={{ color: 'red', fontSize: 15 }}>{loginError}</div>}
          <button type="submit" style={{ background: '#6c63ff', color: '#fff', border: 'none', borderRadius: 4, padding: '10px 0', fontWeight: 700, fontSize: 16, cursor: 'pointer' }}>Login</button>
        </form>
      </div>
    );
  }

  return (
    <div style={{ maxWidth: 900, margin: "40px auto", background: "#fff", borderRadius: 12, padding: 32, color: '#222', boxShadow: '0 2px 16px #0001' }}>
      {/* ── Lightbox ── */}
      {lightbox && (
        <ImageLightbox src={lightbox.src} alt={lightbox.alt} onClose={() => setLightbox(null)} />
      )}

      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <h2 style={{ fontSize: 32, marginBottom: 16, fontWeight: 800, letterSpacing: 1 }}>Admin Feature Management</h2>
        <button onClick={handleLogout} style={{ background: '#e74c3c', color: '#fff', border: 'none', borderRadius: 6, padding: '8px 18px', fontWeight: 700, fontSize: 16, cursor: 'pointer' }}>Logout</button>
      </div>
      <div style={{ marginBottom: 32, color: '#666', fontSize: 18 }}>
        <span>Manage, prioritize, and update all features in one place.</span>
      </div>
      {loading && <p>Loading...</p>}
      {error && (
        <div style={{ color: 'red', marginBottom: 12 }}>
          <p>{error}</p>
          {errorDetails && (
            <details style={{ fontSize: 13, marginTop: 4 }}>
              <summary>Details</summary>
              <pre style={{ whiteSpace: 'pre-wrap' }}>{errorDetails}</pre>
            </details>
          )}
          <button onClick={fetchFeatures} style={{ marginTop: 8 }}>Retry</button>
        </div>
      )}
      <h3 style={{ fontSize: 22, margin: '32px 0 12px 0', fontWeight: 700, color: '#333' }}>Add New Feature</h3>
      <button onClick={() => setAdding(true)} style={{ marginBottom: 24, background: '#6c63ff', color: '#fff', border: 'none', borderRadius: 6, padding: '10px 24px', fontWeight: 700, fontSize: 16, cursor: 'pointer', boxShadow: '0 1px 4px #0001' }}>+ Add Feature</button>
      {adding && (
        <FeatureModal
          feature={null}
          onSave={async (form) => {
            setError(null);
            setLoading(true);
            try {
              const formData = new FormData();
              formData.append("title", form.title);
              formData.append("description", form.description);
              formData.append("priority", form.priority);
              formData.append("status", form.status);
              if (form.image) {
                formData.append("image", form.image);
              }
              const res = await axios.post(API_URL, formData, {
                headers: { "Content-Type": "multipart/form-data" }
              });
              setFeatures(f => [...f, res.data]);
              setNewFeature({ title: "", description: "", priority: "Low", status: "Open" });
              setImageFile(null);
              setLastAddedId(res.data.id || res.data._id);
              setShowPriorityDialog(true);
            } catch (err) {
              setError("Failed to add feature");
              setErrorDetails(err?.message || JSON.stringify(err));
            } finally {
              setLoading(false);
              setAdding(false);
            }
          }}
          onClose={() => setAdding(false)}
        />
      )}
      {/* Priority dialog/modal after add */}
      {showPriorityDialog && lastAddedId && (
        <div style={{
          position: 'fixed', top: 0, left: 0, width: '100vw', height: '100vh',
          background: 'rgba(0,0,0,0.3)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000
        }}>
          <div style={{ background: '#fff', padding: 32, borderRadius: 12, minWidth: 320, boxShadow: '0 2px 16px #0002' }}>
            <h3 style={{ marginBottom: 16 }}>Set Priority for New Feature</h3>
            <select value={priorityToSet} onChange={e => setPriorityToSet(e.target.value)} style={{ marginBottom: 16, width: '100%', padding: 8 }}>
              {priorities.map(p => <option key={p}>{p}</option>)}
            </select>
            <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
              <button
                onClick={async () => {
                  setShowPriorityDialog(false);
                  setLastAddedId(null);
                  try {
                    const feature = features.find(f => f.id === lastAddedId);
                    if (!feature) throw new Error('Feature not found');
                    let data;
                    let config = {};
                    if (feature.image) {
                      data = new FormData();
                      data.append('title', feature.title);
                      data.append('description', feature.description);
                      data.append('priority', priorityToSet);
                      data.append('status', feature.status);
                      if (feature.image instanceof File) {
                        data.append('image', feature.image);
                      }
                      config.headers = { 'Content-Type': 'multipart/form-data' };
                    } else {
                      data = {
                        title: feature.title,
                        description: feature.description,
                        priority: priorityToSet,
                        status: feature.status
                      };
                    }
                    await axios.put(`${API_URL}/${lastAddedId}`, data, config);
                    fetchFeatures();
                  } catch (err) {
                    alert('Failed to update priority.');
                  }
                }}
                style={{ marginRight: 8 }}
              >Save</button>
              <button onClick={() => { setShowPriorityDialog(false); setLastAddedId(null); }}>Cancel</button>
            </div>
          </div>
        </div>
      )}
      <h3 style={{ fontSize: 22, margin: '32px 0 12px 0', fontWeight: 700, color: '#333' }}>All Features</h3>
      <table style={{ width: "100%", borderCollapse: "collapse", background: "transparent", fontSize: 16 }}>
        <thead>
          <tr style={{ background: "#f0f0f0" }}>
            <th style={{ textAlign: "left", padding: "10px 8px" }}>ID</th>
            <th style={{ textAlign: "left", padding: "10px 8px" }}>Title</th>
            <th style={{ textAlign: "left", padding: "10px 8px" }}>Priority</th>
            <th style={{ textAlign: "left", padding: "10px 8px" }}>Status</th>
            <th style={{ textAlign: "left", padding: "10px 8px" }}>Created</th>
            <th style={{ textAlign: "left", padding: "10px 8px" }}>Image</th>
            <th style={{ textAlign: "left", padding: "10px 8px" }}>Actions</th>
          </tr>
        </thead>
        <tbody>
          {features.map(f => (
            <tr key={f.id} style={{ borderBottom: "1px solid #eee" }}>
              <td style={{ padding: "10px 8px" }}>{f.id}</td>
              <td style={{ padding: "10px 8px" }}>
                {editingId === f.id ? (
                  <input value={editData.title} onChange={e => setEditData(d => ({ ...d, title: e.target.value }))} />
                ) : f.title}
              </td>
              <td style={{ padding: "10px 8px" }}>
                {editingId === f.id ? (
                  <select value={editData.priority} onChange={e => setEditData(d => ({ ...d, priority: e.target.value }))}>
                    {priorities.map(p => <option key={p}>{p}</option>)}
                  </select>
                ) : f.priority}
              </td>
              <td style={{ padding: "10px 8px" }}>
                {editingId === f.id ? (
                  <select value={editData.status} onChange={e => setEditData(d => ({ ...d, status: e.target.value }))}>
                    {statuses.map(s => <option key={s}>{s}</option>)}
                  </select>
                ) : f.status}
              </td>
              <td style={{ padding: "10px 8px" }}>{new Date(f.createdAt).toLocaleString()}</td>

              {/* ── Image cell ───────────────────────────────────────────── */}
              <td style={{ padding: "10px 8px" }}>
                {editingId === f.id ? (
                  // Inline edit: show current image + file picker
                  <div style={{ display: "flex", flexDirection: "column", gap: 6, alignItems: "flex-start" }}>
                    {/* Preview: new pick wins, otherwise existing */}
                    {editImageFile ? (
                      <img
                        src={URL.createObjectURL(editImageFile)}
                        alt="new preview"
                        style={{ width: 64, height: 64, objectFit: "cover", borderRadius: 6, border: "2px solid #6c63ff", cursor: "zoom-in" }}
                        onClick={() => setLightbox({ src: URL.createObjectURL(editImageFile), alt: "new preview" })}
                        title="Click to enlarge"
                      />
                    ) : f.image ? (
                      <img
                        src={imgSrc(f.image)}
                        alt="current"
                        style={{ width: 64, height: 64, objectFit: "cover", borderRadius: 6, border: "2px solid #ccc", cursor: "zoom-in" }}
                        onClick={() => setLightbox({ src: imgSrc(f.image), alt: f.title })}
                        title="Current image — click to enlarge"
                      />
                    ) : (
                      <div style={{ width: 64, height: 64, borderRadius: 6, background: "#f4f4f4", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 11, color: "#aaa", border: "1px dashed #ccc" }}>
                        No image
                      </div>
                    )}
                    {/* File input */}
                    <label style={{
                      display: "inline-flex", alignItems: "center", gap: 4,
                      background: "#e0e7ff", border: "none", borderRadius: 4,
                      padding: "4px 10px", fontSize: 13, cursor: "pointer", fontWeight: 600, color: "#4338ca"
                    }}>
                      📁 {editImageFile ? "Change" : f.image ? "Replace" : "Upload"}
                      <input
                        type="file"
                        accept="image/*"
                        style={{ display: "none" }}
                        onChange={e => setEditImageFile(e.target.files[0] || null)}
                      />
                    </label>
                    {editImageFile && (
                      <button
                        onClick={() => setEditImageFile(null)}
                        style={{ fontSize: 11, color: "#e74c3c", background: "none", border: "none", cursor: "pointer", padding: 0 }}
                      >✕ Remove new pick</button>
                    )}
                  </div>
                ) : (
                  // View mode: clickable thumbnail
                  f.image ? (
                    <img
                      src={imgSrc(f.image)}
                      alt={f.title}
                      onClick={() => setLightbox({ src: imgSrc(f.image), alt: f.title })}
                      title="Click to view full image"
                      style={{
                        width: 64, height: 64, objectFit: "cover", borderRadius: 6,
                        cursor: "zoom-in", border: "2px solid #eee",
                        transition: "transform 0.15s, border-color 0.15s",
                        display: "block",
                      }}
                      onMouseEnter={e => { e.currentTarget.style.transform = "scale(1.08)"; e.currentTarget.style.borderColor = "#6c63ff"; }}
                      onMouseLeave={e => { e.currentTarget.style.transform = "scale(1)"; e.currentTarget.style.borderColor = "#eee"; }}
                    />
                  ) : (
                    <span style={{ color: "#ccc", fontSize: 13 }}>—</span>
                  )
                )}
              </td>

              {/* ── Actions cell ─────────────────────────────────────────── */}
              <td style={{ padding: "10px 8px" }}>
                {editingId === f.id ? (
                  <>
                    <button onClick={() => handleSave(f.id)} style={{ marginRight: 6, background: '#4caf50', color: '#fff', border: 'none', borderRadius: 4, padding: '4px 12px', cursor: 'pointer', display: 'inline-flex', alignItems: 'center' }}>
                      <span style={{ marginRight: 4 }}>💾</span>Save
                    </button>
                    <button onClick={() => { setEditingId(null); setEditImageFile(null); }} style={{ background: '#eee', color: '#222', border: 'none', borderRadius: 4, padding: '4px 12px', cursor: 'pointer', display: 'inline-flex', alignItems: 'center' }}>
                      <span style={{ marginRight: 4 }}>✖️</span>Cancel
                    </button>
                  </>
                ) : (
                  <>
                    <button onClick={() => handleEdit(f)} style={{ marginRight: 6, background: '#e0e7ff', border: 'none', borderRadius: 4, padding: '4px 12px', cursor: 'pointer', display: 'inline-flex', alignItems: 'center' }}>
                      <span style={{ marginRight: 4 }}>✏️</span>Edit
                    </button>
                    <button onClick={() => setDeleteConfirm(f.id)} style={{ color: '#fff', background: '#e74c3c', border: 'none', borderRadius: 4, padding: '4px 12px', cursor: 'pointer', display: 'inline-flex', alignItems: 'center' }}>
                      <span style={{ marginRight: 4 }}>🗑️</span>Delete
                    </button>
                    {/* Delete confirmation dialog */}
                    {deleteConfirm === f.id && (
                      <div style={{ position: 'fixed', top: 0, left: 0, width: '100vw', height: '100vh', background: 'rgba(0,0,0,0.3)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 2000 }}>
                        <div style={{ background: '#fff', padding: 32, borderRadius: 12, minWidth: 320, boxShadow: '0 2px 16px #0002', textAlign: 'center' }}>
                          <h4 style={{ marginBottom: 16 }}>Are you sure you want to delete this feature?</h4>
                          <div style={{ display: 'flex', justifyContent: 'center', gap: 16 }}>
                            <button onClick={() => { handleDelete(f.id); setDeleteConfirm(null); }} style={{ background: '#e74c3c', color: '#fff', border: 'none', borderRadius: 4, padding: '8px 18px', fontWeight: 700, cursor: 'pointer' }}>Yes, Delete</button>
                            <button onClick={() => setDeleteConfirm(null)} style={{ background: '#eee', color: '#222', border: 'none', borderRadius: 4, padding: '8px 18px', fontWeight: 700, cursor: 'pointer' }}>Cancel</button>
                          </div>
                        </div>
                      </div>
                    )}
                  </>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
